  const list=useMemo(()=>{let r=P;if(cat!=="all")r=r.filter(p=>p.cat===cat);if(q){const s=q.toLowerCase();r=r.filter(p=>p.name.toLowerCase().includes(s)||p.clinical.toLowerCase().includes(s)||p.variants.some(v=>v.spec.toLowerCase().includes(s)||v.sku.toLowerCase().includes(s)));}return r;},[q,cat]);

